class Solution {
public:
    int numPairsDivisibleBy60(vector<int>& time) {
        int n = time.size();
        vector<int> count(60);
        int res = 0;
        for (int i = 0; i < n; i++) {
            int remainder = time[i] % 60;
            res += count[(60 - remainder) % 60];
            count[remainder]++;
        }
        return res;
    }
};
```

